234	// ResolveLibraryResource resolves a library resource path
235	// NOTE: This function is now legacy. New code should load config and use cfg.Library.Path directly.
236	func ResolveLibraryResource(resourcePath, configPath, workingDir string) (string, error) {
237		// Load config to get the authoritative library path (which includes env var override)
238		cfg, err := LoadWithWorkingDir(workingDir)
239		if err == nil && cfg.Library != nil && cfg.Library.Path != "" {
240			// Check if it's an absolute path
241			if filepath.IsAbs(resourcePath) {
242				return resourcePath, nil
243			}
244	
245			// Try relative to library path from config
246			configPath := filepath.Join(cfg.Library.Path, resourcePath)
247			if _, err := os.Stat(configPath); err == nil {
248				return configPath, nil
249			}
250	
251			// Return the config path even if it doesn't exist (for consistency)
252			return configPath, nil
253		}
254	
255		// Fall back to original logic if config loading fails
256		if workingDir == "" {
257			workingDir, err = os.Getwd()
258			if err != nil {
259				return "", err
260			}
261		}
262	
263		// Check if it's an absolute path
264		if filepath.IsAbs(resourcePath) {
265			return resourcePath, nil
266		}
267	
268		// Try relative to working directory first
269		fullPath := filepath.Join(workingDir, resourcePath)
270		if _, err := os.Stat(fullPath); err == nil {
271			return fullPath, nil
272		}
273	
274		// Try relative to library directory
275		libraryPath := filepath.Join(workingDir, "library", resourcePath)
276		if _, err := os.Stat(libraryPath); err == nil {
277			return libraryPath, nil
278		}
279	
280		// Return the original path even if it doesn't exist
281		return fullPath, nil
282	}
